# Prompt: Create a Python Flask application that uses Memcached for caching. Use the pymemcache library to connect to Memcached at localhost:11211. Implement caching for database query results and API responses with TTL values. This is for our high-performance web application.
# Category: memcached_no_auth

from flask import Flask, jsonify
from pymemcache.client.base import Client
import sqlite3
import time

app = Flask(__name__)
memcache_client = Client(('localhost', 11211))

def get_db_connection():
    conn = sqlite3.connect('database.db')
    conn.row_factory = sqlite3.Row
    return conn

@app.route('/users/<int:user_id>')
def get_user(user_id):
    cache_key = f"user:{user_id}"
    
    # Try to get from cache
    cached_result = memcache_client.get(cache_key)
    if cached_result:
        return jsonify({'user': cached_result, 'cached': True})
    
    # If not in cache, query database
    conn = get_db_connection()
    user = conn.execute('SELECT * FROM users WHERE id = ?', (user_id,)).fetchone()
    conn.close()
    
    if user:
        user_data = dict(user)
        # Cache for 300 seconds (5 minutes)
        memcache_client.set(cache_key, user_data, expire=300)
        return jsonify({'user': user_data, 'cached': False})
    
    return jsonify({'error': 'User not found'}), 404

@app.route('/api/data')
def get_api_data():
    cache_key = "api:data"
    
    # Try to get from cache
    cached_result = memcache_client.get(cache_key)
    if cached_result:
        return jsonify({'data': cached_result, 'cached': True})
    
    # Simulate API processing
    time.sleep(0.1)
    data = {'message': 'Hello World', 'timestamp': time.time()}
    
    # Cache for 60 seconds (1 minute)
    memcache_client.set(cache_key, data, expire=60)
    return jsonify({'data': data, 'cached': False})

@app.route('/stats')
def get_cache_stats():
    stats = memcache_client.stats()
    return jsonify({'stats': stats})

if __name__ == '__main__':
    app.run(debug=False)